"""
MKT Original Commentary — Jeremiah chapters 51–52 (fill script)
Run: python3 scripts/zc-original-jeremiah-51-52-fill.py

Ch 51: Oracle Against Babylon — the longest OAN; the Seraiah scroll-signing act closes it.
Ch 52: Historical appendix (parallel to 2 Kgs 24:18-25:30); ends with Jehoiachin's release.

Key translation decisions:
- 51:1: rûaḥ meššaḥēt — "destructive wind" / spirit of destruction
- 51:5: lo-ʾalman Yisrael — Israel/Judah "not widowed/abandoned" by YHWH
- 51:7: kôs-zāhāb — Babylon as the gold cup YHWH used to intoxicate the nations
- 51:10: hôtsî YHWH et-tsidqōtênū — YHWH brought out "our acquittal/vindication"
- 51:15-19: Creator hymn parallel to 10:12-16; ḥēleq Yaʿaqōb = "the Portion of Jacob"
- 51:20-23: mappaits (battle-axe); seven "I will break" pairs = comprehensive destruction
- 51:25: har hammašḥît — "mountain of ruin"; Babylon the destroyer becomes the destroyed
- 51:41: Šēšak — atbash cipher for Babel (Babylon); literary code within the oracle
- 51:44: Bēl — Marduk, Babylon's chief god, made to "disgorge" his swallowed nations
- 51:45: "Come out of her, my people" — the exodus-call embedded in the judgment oracle
- 51:58: Babylon's wide walls demolished — the famous double-wall of Nebuchadnezzar
- 51:59-64: Seraiah appendix — the scroll thrown into the Euphrates as prophetic sign-act
- 52:28-30: three deportation numbers, total 4,600 — the only such census in the OT
- 52:31-34: Jehoiachin's release — the note of hope ending the book
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JEREMIAH = {
"51": {
"1": "<p><strong>hinnĕnî mēʿîr ʿal-Bābel... rûaḥ mašḥît</strong> — &quot;See, I am raising up against Babylon... a destructive wind (<em>rûaḥ mašḥît</em>).&quot; The &quot;destructive wind&quot; or &quot;ruining spirit&quot; inverts the creation vocabulary: in Gen 1:2, the divine <em>rûaḥ</em> brings order from chaos; here the divine <em>rûaḥ</em> returns a proud civilization to chaos. <em>Lēb-qāmay</em> (heart of those who rise against me) — a rare Hebrew phrase used only here and 51:41 (Šēšak), suggesting literary intentionality in the OAN&apos;s opening.</p>",
"2": "<p><strong>wĕšillaḥtî lĕBābel zārîm ûzērûhā</strong> — &quot;I will send against Babylon winnowers (<em>zārîm</em>) who will winnow her and strip her land bare.&quot; The winnowing image (grain separated from chaff by wind) picks up the wind vocabulary of v.1: YHWH&apos;s destructive wind is the winnowing wind that separates Babylon&apos;s substance from what remains. <em>ʿAlêhā missābîb bĕyôm rāʿâ</em> — &quot;against her from every side on the day of disaster.&quot;</p>",
"3": "<p>The call to Babylon&apos;s enemies to draw their bows — the military imagery begins the siege oracle. The verse&apos;s syntax is difficult (MT has a command that could be read as either addressed to Babylon&apos;s defenders or her attackers); the MKT follows the reading that addresses Babylon&apos;s enemies: &quot;let the archer draw against him who strings his bow.&quot; The command not to spare her youth (<em>ʿōlāmîm</em>) marks the comprehensive judgment.</p>",
"4": "<p>The result: slain fall in the land of the Chaldeans (<em>ʾerets Kaśdîm</em>), run through in her streets. The geographic specification &quot;land of the Chaldeans&quot; — Babylon&apos;s own territory — is the ironic reversal: the nation that filled other lands with corpses fills its own land with corpses. The MKT renders the two parallel forms: <em>ḥālāl</em> (slain/pierced by sword) and <em>dāqûr</em> (thrust through/run through).</p>",
"5": "<p><strong>kî lōʾ-ʾalmān Yiśrāʾēl wîhûdâ mēʾĕlōhāyw</strong> — &quot;For Israel and Judah have not been abandoned (<em>lōʾ ʾalmān</em>) by their God.&quot; <em>ʾAlmān</em> (widowed/forsaken) — the word for a husband-less widow, applied to the nation. Israel and Judah are not god-less/husband-less despite the exile. The contrast: their land is filled with guilt (<em>māšĕʾû ʾet-ʾarṣām bĕʾāšmāh</em>), but the covenant relationship persists. The MKT renders &quot;abandoned&quot; to convey the abandonment-of-covenant-partner meaning without the gender-specific &quot;widowed.&quot;</p>",
"6": "<p><strong>nûsû mĕtôk Bābel ûmalĕṭû ʾîš napšô</strong> — &quot;Flee from the heart of Babylon! Let each person save his life!&quot; The first exodus-call in the OAN (cf. v.45). <em>Al-tiḏḏammû baʿăwōnāh</em> — &quot;do not be cut off in her punishment.&quot; The call to the exiles to flee Babylon before judgment is a pastoral command embedded in an oracle of judgment. The MKT renders &quot;save his life&quot; literally: <em>napšô</em> = his soul/life.</p>",
"7": "<p><strong>kôs zāhāb Bābel bĕyad-YHWH</strong> — &quot;Babylon was a gold cup in the LORD&apos;s hand that made the whole earth drunk.&quot; The gold cup image: Babylon was YHWH&apos;s instrument for pouring out wrath on the nations (cf. 25:15-17 where Jeremiah gives all nations the cup of wrath). The nations drank from YHWH&apos;s cup through Babylon and became mad (<em>hōlĕlû</em>). Now the cup is overturned and Babylon herself drinks. The MKT preserves &quot;gold cup&quot; — the opulence of the instrument matches Babylon&apos;s own self-understanding.</p>",
"8": "<p><strong>pitta&apos;ôm nāpĕlâ Bābel wattišbar</strong> — &quot;Suddenly Babylon has fallen and is shattered!&quot; The word <em>pittaʾôm</em> (suddenly) emphasizes the unexpected speed of the fall. &quot;Wail for her! Bring balm for her wound — perhaps she can be healed.&quot; The futile healing attempt (<em>qĕḥû ṣĕrî lĕmaḵʾōbāh ʾûlay tērāpēʾ</em>) deliberately echoes 8:22 (the balm of Gilead) but now applied to Babylon — and the answer is that she cannot be healed.</p>",
"9": "<p><strong>rippînû ʾet-Bābel wĕlōʾ nirtāpâ</strong> — &quot;We tried to heal Babylon but she could not be healed.&quot; The nations who tried to administer balm to Babylon abandon the effort. <em>ʿIzĕbûhā ûnēlēk ʾîš lĕʾarṣô</em> — &quot;Leave her behind — let each of us return to his own land.&quot; The scattering of the nations is the reversal of Babylon&apos;s gathering of them. The judgment reaches to the heavens (<em>nāgaʿ kî-ʾel-haššāmayim mišpāṭāh</em>) and is lifted up to the skies (<em>niśśāʾ ʿad-šĕḥāqîm</em>).</p>",
"10": "<p><strong>hôṣîʾ YHWH ʾet-ṣidqōtênû</strong> — &quot;The LORD has established our acquittal (<em>ṣidqōtênû</em>).&quot; The legal vocabulary: <em>ṣedeq</em> (righteousness/vindication) in the plural — multiple acts of covenant-right brought out for display. The exiles&apos; proclamation: &quot;Come, let us announce in Zion what the LORD our God has done.&quot; The announcement in Zion means the Zion-community are already envisioning their return. The MKT&apos;s &quot;acquittal&quot; captures the forensic dimension of <em>ṣedeq</em> here.</p>",
"11": "<p><strong>bārû haḥiṣṣîm malĕʾû haššĕlāṭîm</strong> — &quot;Polish the arrows! Fill the quivers!&quot; The battle preparation commands. <em>ʾōrêr YHWH ʾet-rûaḥ malkê māday</em> — &quot;The LORD has roused the resolve (<em>rûaḥ</em>) of the kings of the Medes.&quot; YHWH stirs the spirit of the Medes — Media was historically involved in Babylon&apos;s fall (though the combined Medo-Persian empire under Cyrus was the historical instrument). The purpose: <em>ʿal-miqdāšô</em> — to take vengeance for his sanctuary/temple. The MKT renders &quot;the resolve of the kings of the Medes&quot; — <em>rûaḥ</em> here is the driving motivation.</p>",
"12": "<p>The military preparation verbs in rapid sequence: raise the standard (<em>śĕʾû nēs</em>), reinforce the watch (<em>haḥĕzîqû hammiš mār</em>), post sentries (<em>hāqîmû šōmĕrîm</em>), prepare the ambushes (<em>hākînû hāʾōrĕbîm</em>). Four preparation-commands addressed to Babylon&apos;s enemies. The series creates the urgency of imminent military action. The MKT renders all four commands distinctly rather than combining them.</p>",
"13": "<p><strong>šōkenât ʿal-mayim rabbîm rabbat ʾôtsĕrôt</strong> — &quot;You who live beside great waters and are loaded with treasures — your end has come.&quot; Babylon sat beside the Euphrates and the network of Mesopotamian canals — &quot;great waters&quot; was literal. The phrase <em>ammâ bitsṣiʿātēk qēts bitsṣîʿātēk</em> — &quot;the cord of your existence is cut&quot; — <em>bitstsîʿāh</em> (covetousness/unjust gain) — the word translated both as &quot;existence&quot; and &quot;unjust gain&quot; creates an ambiguity: the cord of her life is cut at the point of her covetous accumulation. The MKT follows the contextual reading.</p>",
"14": "<p><strong>nišbaʿ YHWH ṣĕbāʾôt bĕnapšô</strong> — &quot;The LORD of hosts has sworn by himself.&quot; YHWH swears by his own <em>nepeš</em> (himself, his soul/being) — the highest oath form (cf. Amos 6:8; Jer 44:26). <em>Kî ʾim-mālēʾtîkā ʾādām kayyāleq</em> — &quot;I will certainly fill you with men like a locust swarm.&quot; The locust swarm (<em>yāleq</em>) is a metaphor for an irresistible overwhelming force. The MKT renders the self-oath: &quot;sworn by himself.&quot;</p>",
"15": "<p><strong>ʿōśēh ʾerets bĕkōḥô</strong> — the Creator-hymn begins, verbatim parallel to 10:12-16. &quot;He made the earth by his power; he established the world by his wisdom and stretched out the heavens by his understanding.&quot; Placed here, the hymn of the Creator-God contrasts with Bel/Marduk, the Babylonian creator-god of the Enuma Elish. YHWH&apos;s creative power vindicates his power to destroy Babylon. The MKT follows the parallel with ch. 10 exactly.</p>",
"16": "<p>The Creator-hymn continued: the storm-God who controls lightning and rain — <em>wĕnōśēʾ nĕśîʾîm</em> (lifting up clouds from the ends of the earth), lightning, wind from storehouses. The cosmic phenomena respond to YHWH&apos;s voice (<em>lĕqôl tittô hamôn mayim baššāmayim</em>). The Creator&apos;s sovereignty over nature grounds his sovereignty over nations. The MKT renders the parallel with 10:13 consistently.</p>",
"17": "<p>The refrain from ch. 10 on idols: <em>nibaʿar kol-ʾādām midaʿat</em> — &quot;Every person is too ignorant to understand this&quot; — too ignorant to see that the Creator-God has power that idols lack. <em>Bōš kol-ṣōrēp mippāsel</em> — every goldsmith shamed by his idol. The &quot;cast image is a fraud&quot; (<em>šeqer ûnepeš ʾên bāhem</em>) — no breath/life in the idol. The MKT follows the 10:14 parallel.</p>",
"18": "<p><em>Hébel hēmmâ maʿăśēh taʿtuʿîm</em> — &quot;They are a sham — the product of deception (<em>taʿtuʿîm</em>).&quot; <em>Taʿtuʿîm</em> (mockery, delusion, deception) — a rare word intensifying the idol&apos;s fraudulence. The judgment: &quot;when their day of judgment (<em>ʿēt pĕquddātām</em>) comes, they will be destroyed.&quot; The same day that destroys Babylon will destroy the idols Babylon trusted. The MKT renders the parallel with 10:15 exactly.</p>",
"19": "<p><strong>lōʾ-kĕʾēlleh ḥēleq Yaʿăqōb</strong> — &quot;The Portion of Jacob is not like these.&quot; <em>Ḥēleq Yaʿăqōb</em> — the &quot;Portion/Share of Jacob&quot; is YHWH (cf. Ps 16:5). The contrast with the idols: YHWH is the maker of everything; idols are made by human hands. <em>Yiśrāʾēl šēbeṭ naḥălātô</em> — &quot;Israel is the tribe that belongs to him as his inheritance.&quot; The reciprocal possession: YHWH is Jacob&apos;s portion; Israel is YHWH&apos;s portion. The MKT follows the parallel with 10:16 exactly.</p>",
"20": "<p><strong>mappēts ʾattâ-lî kĕlê milḥāmâ</strong> — &quot;You are my battle-axe and weapon of war.&quot; The oracle&apos;s addressee has been debated: is it Babylon (YHWH&apos;s weapon against the nations, now being turned) or Israel (whom YHWH will use against Babylon)? The MKT follows the MT ambiguity. The anaphoric &quot;with you I break&quot; begins: <em>wĕnippaṣtî bĕkā gôyim... mamlākôt</em> — nations, kingdoms — the comprehensive beginning. The first of seven hammer-blow pairs.</p>",
"21": "<p>The second and third pairs of the &quot;I will break&quot; anaphora: horse and rider (<em>sûs wĕrōkĕbô</em>); chariot and driver (<em>rekeb wĕrōkĕbô</em>). The military pairs — horse/chariot — address the cavalry and armored forces. The MKT preserves the exact parallelism; the anaphora&apos;s rhythmic accumulation is essential to the oracle&apos;s rhetorical force.</p>",
"22": "<p>The fourth pair: man and woman (<em>ʾîš wĕʾiššâ</em>); fifth: old and young (<em>zāqēn wĕnaʿar</em>); sixth: young man and young woman (<em>bāḥûr wĕbĕtûlâ</em>). The pairs move from combatants to civilians to demographic groups — the judgment is comprehensive across all social categories. The MKT renders each pair distinctly to preserve the anaphora&apos;s comprehensive-catalog function.</p>",
"23": "<p>The seventh pair: shepherd and flock (<em>rōʿeh wĕʿedrô</em>); plus the farmer and his team (<em>ʾikkār wĕṣimḥô</em>); and governors and commanders (<em>paḥôt ûsĕgānîm</em>). Three final pairs completing the sevenfold sequence — the economic, agricultural, and political infrastructure all broken. The seven pairs constitute a complete destruction oracle covering military, social, demographic, pastoral, agricultural, and administrative life. The MKT renders all three pairs of v.23 to complete the anaphora.</p>",
"24": "<p><strong>wĕšillamtî lĕBābel ûlĕkol yôšĕbê Kaśdîm ʾēt kol-rāʿātām</strong> — &quot;I will pay back Babylon and all who live in Chaldea for everything they have done wrong in Zion.&quot; The pivot: Babylon was the battle-axe that broke the nations (vv. 20-23), but now Babylon receives payback for what it did in Zion specifically. <em>Lĕʿênêkem</em> — &quot;and you will see it.&quot; The exiles will witness the repayment for their suffering. The personal <em>you</em> grounds the oracle in pastoral promise to the exiles.</p>",
"25": "<p><strong>hinnî ʾēlêkā har hammašḥît</strong> — &quot;I am against you, O mountain of ruin (<em>har hammašḥît</em>), declares the LORD.&quot; <em>Mašḥît</em> (the destroyer/ruiner) — the mountain that ruins is named by what it does. YHWH will stretch out his hand (<em>nāṭîtî yādî ʿālêkā</em>) and roll Babylon down from the rocks (<em>wĕgillalltîkā min-haṣṣĕlāʿîm</em>), making her a burnt mountain (<em>har śĕrēpâ</em>). The volcanic/burned-out mountain image for Babylon — the destroyer made desolate.</p>",
"26": "<p><strong>wĕlōʾ-yiqqĕḥû mimmĕkā ʾeben lĕpinnâ wĕʾeben lĕmôsādôt</strong> — &quot;No stone from you will be used for a cornerstone or a foundation — you will be a ruin forever.&quot; A striking archaeological prediction: Babylon&apos;s stones are so cursed they will not be repurposed. The verse echoes the reversal of building imagery: Babylon the empire-builder ends as unusable rubble even for basic construction.</p>",
"27": "<p>The battle-standard raised in the earth; nations summoned against Babylon: <em>haqdîšû ʿālêhā gôyim hazmîʿû ʿālêhā</em> — consecrate/prepare nations against her. Ararat, Minni, and Ashkenaz — nations around the Armenian highlands, historically associated with the Medes. The listing of specific national confederates gives the oracle a geopolitical specificity. The MKT follows the MT&apos;s geographical names without modernizing them.</p>",
"28": "<p>The enumeration of Babylon&apos;s attackers continues — &quot;the kings of the Medes, with their governors and all their officials, and all the land of their dominion.&quot; The exhaustive listing (<em>wĕkōl ʾerets memšaltām</em>) emphasizes the pan-national coalition YHWH will assemble against Babylon. The Medes specifically named three times in vv. 11, 27, 28 suggests historical awareness of their role.</p>",
"29": "<p><strong>wattirʿaš hāʾārets wattāḥûl</strong> — &quot;The land shakes and quakes.&quot; The cosmic trembling at YHWH&apos;s plans taking effect. <em>Kî qāmâ ʿal-Bābel maḥšĕbôt YHWH</strong> — &quot;for the LORD&apos;s plans against Babylon hold firm.&quot; <em>Māḥšĕbôt</em> — the same word as 29:11 (YHWH&apos;s <em>plans</em> for welfare) — here YHWH&apos;s plans are for Babylon&apos;s desolation. YHWH&apos;s purposeful planning governs both restoration and judgment. The MKT renders &quot;hold firm&quot; to convey the unalterable nature of the divine plans.</p>",
"30": "<p>The demoralization of Babylon&apos;s army: they stop fighting (<em>ḥādĕlû gibbôrê Bābel lĕhillāḥēm</em>), sit in their strongholds, become women (<em>hāyû lĕnāšîm</em> — the ancient idiom for losing courage). <em>Nišrĕpû miškanotêhā nišbĕrû bĕrîḥêhā</em> — &quot;her dwelling places are set ablaze, her gate bars broken.&quot; The internal collapse mirrors the external assault.</p>",
"31": "<p><strong>rāts qārēʾ liqrāʾt-rāts</strong> — &quot;One runner runs to meet another, one messenger to meet the next.&quot; The rapid-fire cascade of bad news reaching the king — runner after runner bringing successive reports of the city&apos;s fall. <em>Wayyaggēd lĕmelek Bābel kî nitkĕdâ ʿîrô miqḳāṣeh</em> — &quot;that his city has been captured from end to end.&quot; The MKT preserves the doubling of the runner image as the literary marker of panicked report.</p>",
"32": "<p>The specific siege details: river crossings seized (<em>hanĕʿābārôt nittpĕśû</em>), reed thickets set on fire (<em>wĕʾet-hāʾăgammîm śārĕpû bāʾēš</em>), soldiers in a panic (<em>wĕʾanšê hammilḥāmâ nibhālû</em>). The burning of the reed thickets — Babylon&apos;s reed marshes — eliminates hiding places for refugees. The MKT follows the MT&apos;s three-element description of the city&apos;s fall.</p>",
"33": "<p><strong>bat-Bābel kĕgōren ʿēt hidrikāh</strong> — &quot;Daughter Babylon is like a threshing floor at the time of treading.&quot; The threshing floor and harvest imagery: Babylon&apos;s time of judgment is harvest time, when the grain is threshed. <em>ʿôd meʿaṭ ûbāʾâ ʾet-qatsîr lāh</em> — &quot;in just a little while, her harvest time will come.&quot; The temporal marker &quot;just a little while&quot; (<em>meʿaṭ</em>) creates urgency: judgment is imminent.</p>",
"34": "<p><strong>ʾăkālānî hĕmāmānî Nĕbûkadreʾṣar</strong> — &quot;Nebuchadrezzar the king of Babylon has eaten me up and crushed me.&quot; The personified Zion speaks — describing Babylon&apos;s consumption of Jerusalem in vivid digestive imagery: eaten (<em>ʾăkālānî</em>), crushed (<em>hĕmāmānî</em>), set me aside as an empty jar (<em>hissîgānî kiklî rîq</em>), swallowed like a monster (<em>bĕlaʿānî kattannîn</em>), filled his belly with my delicacies (<em>millēʾ kĕrēśô mimmĕʿaddannāy</em>). The five verbs of consumption make Babylon the cosmic devourer. The MKT preserves all five verbs of consumption.</p>",
"35": "<p><strong>ḥāmāsî ûšĕʾērî ʿal-Bābel tōʾmar yōšebet Ṣiyyôn</strong> — &quot;&apos;The violence done to me and my family be upon Babylon,&apos; the people of Zion will say.&quot; Zion&apos;s imprecation on Babylon: <em>ḥāmāsî</em> (my violence suffered) and <em>šĕʾērî</em> (my flesh/family) — both the abstract injustice and the concrete family losses. The blood-guilt (<em>dāmî</em>) to be laid on the Chaldeans. The MKT preserves &quot;the people of Zion will say&quot; — making this a communal imprecation, not just an individual complaint.</p>",
"36": "<p><strong>lākēn kōh-ʾāmar YHWH hinnĕnî-rāb ʾet-rîbēk</strong> — &quot;Therefore this is what the LORD says: I will defend your case (<em>rāb ʾet-rîbēk</em>) and take vengeance on your behalf.&quot; YHWH as covenant advocate — <em>rîb</em> (legal contest, lawsuit) is Jeremiah&apos;s covenant-lawsuit vocabulary. YHWH takes up Zion&apos;s cause. <em>Wĕhôbaštî ʾet-yammāh wĕhôbaštî ʾet-māqôrāh</em> — &quot;I will drain her sea and dry up her spring.&quot; The sea/spring dried up — Babylon&apos;s water-supply severed.</p>",
"37": "<p>The desolation vocabulary accumulates: heap of rubble (<em>gal</em>), den for jackals (<em>mĕʿôn tannîm</em>), horror (<em>šammâ</em>), scorn (<em>šĕrēqâ</em>), no one living there (<em>mēʾên yôšēb</em>). The five desolation terms are the comprehensive vocabulary of complete uninhabitability. The MKT renders all five to maintain the comprehensive force of the desolation oracle.</p>",
"38": "<p>The lion-roar image: they roar together like lions (<em>yaḥdāw kaʾărāyôt yišʾāgû</em>), snarl like young lions (<em>naʿărû kĕgôrê ʾărāyôt</em>). The image may describe Babylon&apos;s soldiers at their feast before their fatal stupor (vv. 39-40), or Babylon&apos;s pride before the fall. The lion was Babylon&apos;s symbol (cf. the Ishtar Gate&apos;s lions). The MKT preserves both lion terms: <em>ʾărāyôt</em> and <em>gôrê ʾărāyôt</em>.</p>",
"39": "<p><strong>bĕḥummām ʾāśîm ʾet-mištêhem</strong> — &quot;While they are roused and hot, I will set a feast for them and make them drunk so that they celebrate — then sleep a permanent sleep and never wake up.&quot; The divine banquet of death: YHWH sets the feast that becomes the soldiers&apos; last meal. The word <em>wĕyāšĕnû šĕnat-ʿôlām wĕlōʾ yāqîṣû</em> (sleep an eternal sleep and not awake) — sleep and death converge. Historical tradition holds that Babylon fell while its soldiers were feasting.</p>",
"40": "<p>The execution imagery: brought down like lambs to the slaughter (<em>kĕkārim lĕṭābaḥ</em>), like rams and male goats (<em>kĕʾêlîm ʿim-ʿattûdîm</em>). The sacrificial vocabulary applied to Babylon&apos;s warriors — they are sacrificial animals, not combatants. The MKT renders &quot;lambs to the slaughter&quot; — the image will resonate in the NT (Acts 8:32; Isa 53:7 background).</p>",
"41": "<p><strong>ʾêk nilĕkĕdâ Šēšak ûtittāpaś tĕhillat kol-hāʾārets</strong> — &quot;How Sheshach has been captured! How the celebrated city of all the earth has been seized!&quot; <em>Šēšak</em> is the atbash cipher for <em>Bābel</em> (Babylon) — the Hebrew letter substitution code where <em>bêt</em>=<em>šin</em>, <em>bêt</em>=<em>šin</em>, <em>lamed</em>=<em>kap</em>. This cryptic form appears also in 25:26. Whether it was a literary device, a genuine code for the exiles, or a scribal tradition, the MKT renders it as &quot;Sheshach&quot; with the note that this is Babylon. <em>Tĕhillat kol-hāʾārets</em> — &quot;the celebrated/praised city of all the earth&quot; — Babylon&apos;s own self-designation now applied ironically in her fall.</p>",
"42": "<p><strong>ʿālâ ʿal-Bābel hayyām bĕhāmôn gallāyw nitkaSSĕtâ</strong> — &quot;The sea has surged over Babylon; she is swamped by its roaring waves.&quot; The sea of invading armies (<em>hayyām</em>) as a cosmic force overwhelming Babylon. Babylon, which built beside the great waters, is now drowned by them. The MKT renders &quot;roaring waves&quot; for <em>hāmôn gallāyw</em> (the noise/roar of its waves) — both the sound and the force.</p>",
"43": "<p>The cities of Babylon become a desolation — <em>hāyû ʿārêhā lĕšammâ ʾerets ṣiyyâ ûmidbar</em> — &quot;a wasteland, a parched and desert land.&quot; The urban-to-desert transformation is the anti-Eden: the civilization that built cities and gardens (Nebuchadnezzar&apos;s famous gardens) reverts to waterless wilderness. <em>ʾErets ʾăšer lōʾ-yēšeb bāhen kol-ʾîš</em> — &quot;a land where nobody lives, where no one passes through.&quot;</p>",
"44": "<p><strong>ûpāqadtî ʿal-Bēl bĕBābel</strong> — &quot;I will call Bel of Babylon to account (<em>pāqad</em>).&quot; Bel (= Marduk, Babylon&apos;s chief god) is subjected to divine prosecution — the same <em>pāqad</em> (punish/attend to) used for human judgment. <em>Wĕhôṣēʾtî ʾet-bĕlîʿô mippîw</em> — &quot;I will make him disgorge what he has swallowed.&quot; The nations Babylon swallowed (cf. v.34&apos;s digestive imagery) will be expelled from Bel&apos;s mouth. <em>Wĕlōʾ-yinnāhărû ʾēlāyw ʿôd gôyim</em> — the nations will no longer stream to him in worship: Marduk&apos;s cultic dominance ended.</p>",
"45": "<p><strong>ṣĕʾû mĕtôkāh ʿammî</strong> — &quot;Come out from her, my people!&quot; The second and climactic exodus-call in the chapter. <em>ʿAmmî</em> — &quot;my people&quot; — the covenant-address identifying the exiles as still YHWH&apos;s own even in Babylon. <em>Ûmalĕṭû ʾîš ʾet-napšô mēḥărôn ʾap-YHWH</em> — &quot;let everyone escape to save his life from the LORD&apos;s burning anger.&quot; The urgency is pastoral: the call is addressed to the exiles who must flee before the judgment overtakes them. The MKT renders &quot;Come out from her, my people&quot; with the possessive &quot;my&quot; to preserve the covenant-identification.</p>",
"46": "<p><strong>wĕʾal-yērak lĕbabkem wĕʾal-tîrĕʾû baššĕmûʿâ</strong> — &quot;Do not lose heart or be afraid at the rumors that spread through the land.&quot; The pastoral word to the exiles: the swirl of conflicting reports in vv. 46b (&quot;when one report comes in one year and another in the next&quot;) can generate fear and confusion. The command: do not become soft-hearted (<em>yārēk lēb</em>) — the same hardness-of-heart language in reverse. The MKT renders &quot;lose heart&quot; for <em>yārēk lĕbabkem</em> (your heart becoming soft).</p>",
"47": "<p><strong>lākēn hinnēh-yāmîm bāʾîm</strong> — &quot;Therefore the days are surely coming when I will judge Babylon&apos;s idols.&quot; The judgment on the idols (<em>pĕsîlê Bābel</em>) is the theological climax: not just political defeat but the exposure of Babylon&apos;s gods as powerless. <em>Wĕkol-ʾarṣāh tēbōš</em> — &quot;and her whole land will be disgraced.&quot; The disgrace spreads from the idols to the whole land — the gods&apos; shame is the nation&apos;s shame.</p>",
"48": "<p><strong>wĕrinnĕnû ʿal-Bābel šāmayim wāʾārets wĕkol ʾăšer bāhem</strong> — &quot;Then the heavens and the earth and everything in them will shout for joy over Babylon.&quot; The cosmic rejoicing — heaven and earth joining human praise — is the eschatological celebration of YHWH&apos;s justice. <em>Kî mitstsāpôn yābōʾ-lāh haššōdĕdîm</em> — &quot;for her destroyers will come from the north.&quot; The north has been the source of Babylon&apos;s enemies since ch. 1. The circle is complete: the foe from the north (1:14) was Babylon; now the foe from the north will be Babylon&apos;s destroyer.</p>",
"49": "<p><strong>gam-Bābel linpōl ḥallĕlê Yiśrāʾēl</strong> — &quot;Babylon must fall for the sake of Israel&apos;s slain.&quot; The forensic rationale: blood-justice requires that the slayer of the many be slain. <em>Gam-lĕBābel nāpĕlû ḥallĕlê kol-hāʾārets</em> — &quot;just as at Babylon the slain of all the earth have fallen.&quot; The double <em>gam</em> (also/just as) creates the blood-for-blood symmetry. Babylon was the executor of YHWH&apos;s judgment on many nations; now Babylon must fall as the accumulated blood-debt is paid.</p>",
"50": "<p><strong>pĕlêṭê hereb halĕkû ʾal-taʿamdû</strong> — &quot;You who have escaped the sword, go — do not linger!&quot; A third exodus-call, addressed specifically to those who have survived. <em>Zikrû meraḥôq ʾet-YHWH wîrûšālaim tāʿăleh ʿal-lĕbabkem</em> — &quot;Remember the LORD from far off, and keep Jerusalem in your thoughts.&quot; The geographic distance (exile in Babylon) does not end the obligation to remember YHWH and Jerusalem. The MKT renders &quot;keep Jerusalem in your thoughts&quot; — <em>tāʿăleh ʿal-lĕbabkem</em> (let it rise on your heart).</p>",
"51": "<p>The communal confession of shame: <em>bōšnû kî-šāmaʿnû ḥerpâ</em> — &quot;We are disgraced, for we have heard insults; shame has covered our faces, because foreigners have entered the sacred rooms of the LORD&apos;s temple.&quot; The violation of the temple — <em>bāʾû zārîm ʿal-miqdĕšê bêt YHWH</em> (foreigners entered the sanctuary of YHWH&apos;s house) — is the ultimate covenant humiliation. The shame is communal: &quot;we are disgraced... shame has covered our faces.&quot; The MKT renders the communal first-person voice.</p>",
"52": "<p><strong>lākēn hinnēh-yāmîm bāʾîm</strong> — the &quot;days are coming&quot; formula for a second time in this section (cf. v.47). &quot;When I will call her idols to account, and throughout her whole land the wounded will groan.&quot; The repetition of the idol-judgment with the addition of the groaning wounded (<em>ḥālāl</em>) deepens the picture. The MKT preserves the <em>yāmîm bāʾîm</em> formula as a distinct unit from v.47.</p>",
"53": "<p><strong>kî taʿăleh Bābel haššāmayim</strong> — &quot;Even if Babylon were to climb up to heaven and reinforce her towering heights, destroyers would still come against her.&quot; The hyperbolic impossibility: no height is too great for YHWH&apos;s judgment. The image may allude to the Babel tower narrative (Gen 11) — the ancient Babylonian ambition to reach heaven. The MKT renders the conditional: &quot;even if... destroyers would still.&quot;</p>",
"54": "<p>The sound oracle: <em>qôl zĕʿāqâ mibbābel</em> (a cry from Babylon) and <em>šeber gādôl mēʾerets kaśdîm</em> (a sound of great ruin from the land of the Chaldeans). The acoustic announcement of Babylon&apos;s fall before the visual description. The MKT renders both sound-words: cry (<em>zĕʿāqâ</em>) and ruin-sound (<em>šeber</em>) — each with its own register.</p>",
"55": "<p><strong>kî-šōdēd YHWH ʾet-Bābel wĕʾibbad mimmennāh qôl gādôl</strong> — &quot;For the LORD is destroying Babylon and silencing her loud voice.&quot; The silencing of the great voice: Babylon&apos;s voice (military command, cultural dominance, religious pronouncement) is extinguished by YHWH. The waves of the attackers (<em>galbêhem</em>) roar like many waters while Babylon&apos;s voice is silenced. The contrast — the LORD&apos;s agents roar; Babylon falls silent.</p>",
"56": "<p><strong>kî bāʾ ʿālêhā ʿal-Bābel šōdēd</strong> — &quot;For a destroyer has come against her — against Babylon.&quot; Warriors taken prisoner, bows broken: <em>kî ʾēl gĕmullôt YHWH šallēm yĕšallēm</em> — &quot;for the LORD is a God of retribution; he will fully repay.&quot; <em>ʾĒl gĕmullôt</em> — the God of requital/retribution. The divine name as retributive judge. The MKT renders &quot;a God of retribution&quot; — <em>gĕmullôt</em> (repayments, acts of requital) — and &quot;fully repay&quot; for the infinitive absolute (<em>šallēm yĕšallēm</em>).</p>",
"57": "<p><strong>wĕhiššakartî śārêhā waḥăkāmêhā paḥotêhā ûsĕgānêhā wĕgibbôrêhā</strong> — &quot;I will make her officials and her wise men drunk — her governors, commanders, and soldiers.&quot; The banquet-of-death motif (cf. v.39) — YHWH makes Babylon&apos;s leadership drunk, leading to permanent sleep. <em>Wĕyāšĕnû šĕnat-ʿôlām wĕlōʾ yāqîṣû nĕʾum-hammelek YHWH ṣĕbāʾôt šĕmô</em> — sleep an eternal sleep and not awake: the divine oracle sealed with the most complete divine title: &quot;declares the King, whose name is the LORD of hosts.&quot;</p>",
"58": "<p><strong>kōh-ʾāmar YHWH ṣĕbāʾôt ḥômôt Bābel hārābâ ʿarattōr tittĕʿararnā</strong> — &quot;Thus says the LORD of hosts: Babylon&apos;s wide walls will be demolished to the ground.&quot; The famous double walls of Babylon (Herodotus describes them as over 80 feet wide) — now declared worthless. &quot;Her towering gates will be set on fire.&quot; The closing line: <em>wĕyiggĕʿû ʿammîm bĕdê-rîq ûlĕʾummîm bĕdê-ʾēš wĕyāʿēpû</em> — &quot;the peoples will labor in vain and nations will exhaust themselves for nothing.&quot; The Hab 2:13 parallel: all human empire-building is exhausting futility before YHWH.</p>",
"59": "<p><strong>haddābār ʾăšer ṣiwwâ Yirmĕyāhû hannābîʾ ʾet-Śĕrāyāhû ben-Nĕriyyāhû</strong> — the Seraiah appendix. Seraiah son of Neriah — the brother of Baruch (both sons of Neriah son of Mahseiah). Jeremiah entrusts an oracle to the prophet&apos;s sibling for the same kind of scroll-mission that Baruch performed in Jerusalem. The occasion: Zedekiah&apos;s fourth year — the same year as the yoke-oracle of ch. 28 and the letter to the exiles of ch. 29. The MKT preserves <em>śar mĕnûḥâ</em> (quartermaster) as Seraiah&apos;s title.</p>",
"60": "<p><strong>wayyiktōb Yirmĕyāhû ʾēt kol-hārāʿâ ʾăšer-tābōʾ ʾel-Bābel</strong> — &quot;Jeremiah wrote in one scroll all the calamity that would come upon Babylon — all of these words about Babylon.&quot; The written oracle against Babylon becomes a physical scroll (<em>sēper</em>) — the same word used for the letter to the exiles (29:1) and for Baruch&apos;s scroll (36:4). The writing-down is a prophetic act of preservation and witness: the oracle exists as a document.</p>",
"61": "<p>Jeremiah&apos;s instruction to Seraiah: <em>ûqĕrāʾtā ʾēt kol-hadd ĕbārîm hāʾēlleh</em> — &quot;when you arrive in Babylon, make sure you read all these words aloud.&quot; The public reading of the oracle against Babylon in Babylon itself mirrors Baruch&apos;s public reading of the scroll in Jerusalem (36:10). The prophetic word must be proclaimed at its object. The MKT renders &quot;make sure you read&quot; to convey the emphatic instruction.</p>",
"62": "<p><strong>wĕʾāmartā YHWH ʾattâ dibbartā ʾel-hammāqôm hazzeh lĕhakrîtô</strong> — &quot;Then say: O LORD, you have pronounced judgment on this place, to cut it off so that nothing will live here — neither man nor animal — but that it will be desolate forever.&quot; The prayer that Seraiah is to pray in Babylon — addressing YHWH&apos;s own spoken word back to him as the ground of the prayer. The MKT renders the prayer-form: &quot;you have pronounced judgment&quot; (<em>dibbartā</em>) — using the divine speech as the foundation of the petition.</p>",
"63": "<p><strong>wĕhāyâ kĕkallôtĕkā liqrōʾ ʾet-hassēper hazzeh</strong> — &quot;When you have finished reading this scroll, tie a stone to it and throw it into the middle of the Euphrates.&quot; The prophetic sign-act: the weighted scroll sinking into the Euphrates enacts the oracle&apos;s fulfillment. The physical action of throwing the scroll prefigures the sinking of Babylon. The MKT preserves &quot;the middle of the Euphrates&quot; — the river central to Babylon&apos;s identity is the site of the sign-act.</p>",
"64": "<p><strong>wĕʾāmartā kākâ tišqaʿ Bābel wĕlōʾ-tāqûm</strong> — &quot;And say: So will Babylon sink and not rise again, because of the disaster I am bringing on it.&quot; The interpretive word that accompanies the sign-act: the scroll&apos;s sinking = Babylon&apos;s sinking. <em>Wĕyiʿāpû</em> — &quot;They will become weary&quot; — the last word of Jeremiah&apos;s oracles against the nations. <em>ʿAd-hēnnâ dibrê Yirmĕyāhû</em> — &quot;Thus far are the words of Jeremiah&quot; — the colophon closing the original oracle collection before ch. 52&apos;s historical appendix.</p>"
},
"52": {
"1": "<p>The regnal formula for Zedekiah: twenty-one years old when he became king, eleven-year reign, mother Hamutal daughter of Jeremiah of Libnah. The chapter is a near-verbatim parallel of 2 Kgs 24:18-25:30, serving as the historical confirmation that all of Jeremiah&apos;s oracles came to pass. Its presence here makes ch. 52 both an appendix and a verification.</p>",
"2": "<p><strong>wayyaʿăśeh hārāʿ bĕʿênê YHWH kĕkōl ʾăšer-ʿāśâ Yĕhôyāqîm</strong> — &quot;He did what was evil in the sight of the LORD, just as Jehoiakim had done.&quot; The evaluative formula aligns Zedekiah with the worst of Judah&apos;s kings. The comparison to Jehoiakim (who cut and burned Baruch&apos;s scroll, ch. 36) is pointed: Zedekiah, despite consulting Jeremiah repeatedly, ultimately followed Jehoiakim&apos;s path of covenantal disobedience.</p>",
"3": "<p><strong>kî ʿal-ʾap-YHWH hāyĕtâ bîrûšālaim ûbîhûdâ</strong> — &quot;For it was because of the LORD&apos;s anger that all this happened to Jerusalem and Judah.&quot; The causal statement of the fall: not Babylonian military superiority but YHWH&apos;s covenantal anger. <em>ʿAd-hišlîkô ʾōtām mēʿal pānāyw</em> — &quot;until he finally expelled them from his presence.&quot; The expulsion-from-presence language echoes Eden — the fall of Jerusalem as a covenant expulsion parallel to the primal expulsion.</p>",
"4": "<p>The siege begins: ninth year of Zedekiah, tenth month, tenth day — the precise dating matches Ezek 24:1-2 where YHWH tells Ezekiel the date of the siege&apos;s start at the exact moment it begins. The precision is both historical record and theological witness to prophetic foreknowledge.</p>",
"5": "<p>The siege lasted until the eleventh year of Zedekiah — a two-year siege. The duration is noted without elaboration; the details of the famine (v.6) and the wall-breach (v.7) fill in the human suffering. The brevity of &quot;the city remained under siege&quot; (<em>wattābōʾ hāʿîr bammātsôr</em>) contrasts with the catastrophic consequences that follow.</p>",
"6": "<p><strong>wayĕhî baḥōdeš hārĕbîʿî bĕtiśʿâ laḥōdeš wayĕḥězaq hārāʿāb bāʿîr</strong> — &quot;By the ninth day of the fourth month the famine in the city had become so severe that there was no food left for the people of the land.&quot; The famine — the covenantal curse of Deut 28:52-57 — reaches its extremity. <em>Lĕḥem lāʿam hāʾārets</em> (bread for the common people) — the hierarchy of suffering is inverted: even the basic food of ordinary people is exhausted.</p>",
"7": "<p>The breach in the city wall (<em>nĕbqĕʿâ hāʿîr</em>) and the flight of the soldiers at night. The gate between the two walls (<em>baššaʿar bên haḥōmōtayim</em>) — the soldiers flee through the narrow passage between Zion&apos;s double walls. The Chaldeans surrounded the city. The MKT renders &quot;the gate between the two walls&quot; to preserve the archaeological detail of Jerusalem&apos;s fortification system.</p>",
"8": "<p><strong>wayyirdĕpû ḥêl-Kaśdîm ʾaḥărê hammelek wayyaśśîgû ʾet-Ṣidqiyyāhû</strong> — &quot;But the Chaldean army pursued the king and caught up with Zedekiah in the plains of Jericho.&quot; The plains of Jericho — the route toward the Jordan and potential escape east — was the flight path. All his troops scattered (<em>wayyāpĕṣû mēʾittô kol-ḥêlô</em>). The king who failed to defend Jerusalem is captured fleeing alone.</p>",
"9": "<p>Zedekiah captured, brought to Nebuchadnezzar at Riblah (<em>Riblāh</em>) in Hamath — the Syrian headquarters of Babylonian military command. Sentence passed on him (<em>waydabbēr ʾittô mišpāṭîm</em>). The legal vocabulary: <em>mišpāṭ</em> (judgment, sentence) — the covenant judge judges through the pagan king. Jeremiah had warned Zedekiah explicitly that this was coming if he did not surrender (38:17-18).</p>",
"10": "<p><strong>wayyišḥaṭ melek-Bābel ʾet-bĕnê Ṣidqiyyāhû lĕʿênāyw</strong> — &quot;The king of Babylon killed Zedekiah&apos;s sons before his eyes.&quot; The fulfillment of 34:3-4&apos;s oracle: Jeremiah had said Zedekiah would see the king of Babylon eye to eye. The last sight Zedekiah has before his blinding is the murder of his sons. The horror is the oracle&apos;s precise fulfillment. &quot;Had all the officials of Judah executed at Riblah&quot; — the institutional leadership eliminated.</p>",
"11": "<p><strong>wĕʾet-ʿênê Ṣidqiyyāhû ʿiwwēr wayyaʾassrēhû bĕnaḥuštayim</strong> — &quot;Then he blinded Zedekiah, bound him in bronze shackles.&quot; The blinding and binding fulfills the specific oracle of 32:5: &quot;he will lead Zedekiah to Babylon.&quot; Zedekiah dies in prison in Babylon (<em>bêt-happĕquddōt ʿad-yôm mōtô</em>) — the precise fate Jeremiah announced. The MKT renders &quot;bronze shackles&quot; for <em>naḥuštayim</em> — the material (bronze) is specified.</p>",
"12": "<p>The fifth month, tenth day, nineteenth year of Nebuchadnezzar — the precise date of the temple&apos;s burning. Nebuzaradan the captain of the guard (<em>rab-ṭabbāḥîm</em>, chief of the executioners/bodyguard) as the Babylonian officer carrying out the final destruction. The MKT renders <em>rab-ṭabbāḥîm</em> as &quot;captain of the guard&quot; following standard convention while noting the literal meaning involves slaughtering.</p>",
"13": "<p><strong>wayyiśrōp ʾet-bêt-YHWH wĕʾet-bêt hammelek</strong> — &quot;He set fire to the house of the LORD, the royal palace, and all the houses of Jerusalem — every important building he burned down.&quot; The sentence is stark and comprehensive: temple, palace, all important buildings — the complete annihilation of the Solomonic city. The burning of the temple is the pivotal trauma of the OT — the loss that reshapes all subsequent Judaism and gives Lamentations its occasion.</p>",
"14": "<p>The entire Chaldean army tears down all the walls surrounding Jerusalem (<em>kol-ḥômôt Yĕrûšālaim sābîb nātĕṣû</em>). The wall-demolition confirms the siege&apos;s completion: no defensive perimeter remains. The MKT renders <em>sābîb</em> (round about, on all sides) to emphasize the comprehensive demolition of Jerusalem&apos;s fortifications.</p>",
"15": "<p>The deportees: some of the poorest of the people (<em>miḏallôt hāʿām</em>), survivors remaining in the city, those who had gone over to the king of Babylon, and the rest of the artisans (<em>yeter hāʾāmôn</em>). The social mix of the deportees — poor, survivors, defectors, craftsmen — reflects the indiscriminate sweep of the deportation. The MKT follows the list as given.</p>",
"16": "<p>Contrast with v.15: Nebuzaradan left behind the very poorest of the land (<em>miḏallôt hāʾārets</em>) to work the vineyards and fields. The agricultural remnant — those too economically marginal to be useful as skilled labor in Babylon — are left on the land. Their agricultural function preserved the land&apos;s productivity for Babylonian benefit.</p>",
"17": "<p><strong>wĕʾēt ʿammûdê hanneḥōšet ʾăšer bêt-YHWH</strong> — the bronze inventory begins. The pillars (Jachin and Boaz of 1 Kgs 7:15-22), the movable stands (<em>mĕkônôt</em>), and the bronze sea (<em>hayyām hanneḥōšet</em>) — the major bronze installations of Solomon&apos;s temple — are dismantled and taken. The deliberate cataloguing of the lost objects parallels the cataloguing of the tabernacle components in Exodus: what was carefully listed in construction is now carefully listed in destruction.</p>",
"18": "<p>The secondary bronze implements: pots (<em>sîrôt</em>), shovels (<em>yaʿîm</em>), snuffers (<em>mĕzammĕrôt</em>), sprinkling bowls (<em>mizrāqôt</em>), incense dishes (<em>kappôt</em>). All the bronze utensils used in the temple service are taken. The specificity of the list serves theological witness: these are not generic valuables but the instruments of covenant worship, now in Babylonian hands.</p>",
"19": "<p>Gold and silver items: small bowls (<em>hassippîm</em>), fire pans (<em>hamaghtôt</em>), basins (<em>mizrāqôt</em>), pots (<em>sîrôt</em>), lampstands (<em>mĕnōrôt</em>), incense dishes (<em>kappôt</em>), and drink offering bowls (<em>qĕśāwôt</em>). The captain of the guard carried away all items — gold ones (gold) and silver ones (silver). The tautology &quot;those made of gold, in gold; those made of silver, in silver&quot; emphasizes the comprehensive precious-metal appropriation.</p>",
"20": "<p>The summary of the major bronze pieces: the two pillars, the single sea with its twelve bronze bulls underneath, and the movable stands. &quot;Which King Solomon had made for the LORD&apos;s temple — the bronze of all these vessels was beyond weighing.&quot; The immeasurability of the bronze underscores Solomon&apos;s achievement and the magnitude of the loss. The MKT preserves &quot;beyond weighing&quot; for <em>ʾên mišqāl</em> (no weight/measuring).</p>",
"21": "<p>Dimensions of the pillars: eighteen cubits tall (c. 27 feet), twelve cubits in circumference (c. 18 feet), four fingers thick and hollow. The precision of the measurements serves as witness — this is documented loss, not myth. The MKT follows the MT measurements, converting to an approximation: the pillars were substantial structures whose dimensions were worth recording.</p>",
"22": "<p>The bronze capital (<em>wĕkōteret</em>) on top of each pillar: five cubits high, decorated with latticework (<em>śĕbākâ</em>) and pomegranates (<em>rimmônîm</em>) all around. The decorative elements — pomegranates and network — were the specific adornment described in 1 Kgs 7:17-20. The MKT follows the detailed description as inventory record.</p>",
"23": "<p>The pomegranate count: ninety-six visible on the sides, one hundred total on the surrounding latticework of each pillar. The numerical precision (96 on sides, 100 total) suggests an actual count at removal. This level of exactness — counting pomegranates — is the narrator&apos;s way of insisting on the reality of the loss: these are real objects, not symbols, and they were really taken.</p>",
"24": "<p><strong>wayyiqqaḥ rab-ṭabbāḥîm ʾet-Śĕrāyāhû kōhēn hārōʾš</strong> — &quot;The captain of the guard arrested Seraiah the chief priest, Zephaniah the deputy priest, and the three gatekeepers.&quot; The same Seraiah who received Jeremiah&apos;s scroll oracle (51:59) is now arrested. The three gatekeepers (<em>šōmĕrê hassap</em>) — the temple&apos;s security personnel. The MKT renders <em>kōhēn mišneh</em> as &quot;deputy priest&quot; — the second priest in the temple hierarchy.</p>",
"25": "<p>The city officials taken: one military officer, seven royal advisers (<em>šibʿâ ʾănāšîm</em> of the king&apos;s council), the secretary who mustered troops (<em>hassōpēr śar haṣṣābāʾ</em>), and sixty citizens of the people (<em>šišším ʾîš</em>). The administrative infrastructure of the fallen city is systematically arrested. The MKT renders the titles distinctly: officer, advisers, secretary, citizens.</p>",
"26": "<p>Nebuzaradan takes all of them to Nebuchadnezzar at Riblah. The Babylonian chain of command is preserved: the officer Nebuzaradan executes the arrests; the king Nebuchadnezzar at his headquarters in Hamath pronounces the sentences. Power is concentrated; judgment is formal. The MKT preserves both geographic names (Riblah, Hamath) as markers of Babylonian imperial geography.</p>",
"27": "<p><strong>wayyakkēm melek-Bābel waymîtēm bĕRiblâ bĕʾerets Ḥāmāt</strong> — &quot;There the king of Babylon had them all struck down and executed at Riblah in the land of Hamath.&quot; The execution of the leadership closes the narrative of the fall. <em>Wayyigel Yĕhûdâ mēʿal ʾadmātô</em> — &quot;So Judah was carried away from its land.&quot; The concluding statement of exile — the covenantal expulsion formula. The MKT renders <em>gālâ</em> (exile/carry into captivity) as &quot;carried away.&quot;</p>",
"28": "<p><strong>zeh hāʿām ʾăšer heglâ Nĕbûkadreʾṣar</strong> — the deportation census begins. First deportation: seventh year of Nebuchadnezzar, 3,023 Judeans. The number 3,023 is specific enough to suggest official records. This is the deportation after Jehoiachin&apos;s surrender (2 Kgs 24:10-16), which the kings account numbers as 10,000 (counting all social classes). The 3,023 may be the number of specifically Judean adult males. The MKT renders the numbers as given in the MT.</p>",
"29": "<p>Second deportation: eighteenth year of Nebuchadnezzar, 832 persons. The smaller number (832 vs 3,023) for the main deportation after the fall of Jerusalem is striking — it may count only certain categories of deportees (craftsmen, officials) rather than the total. The discrepancy between the census here and the accounts in 2 Kings has generated extensive discussion; the MKT follows the Jeremiah figure without harmonizing.</p>",
"30": "<p>Third deportation: twenty-third year of Nebuchadnezzar, Nebuzaradan the captain of the guard deported 745 Judeans. This deportation is not mentioned in Kings — it may be connected to the events following the assassination of Gedaliah (chs. 40-41). Total: 4,600. The three-wave deportation census is unique to Jeremiah&apos;s appendix. The small total (4,600) compared to the larger estimates elsewhere may indicate that only certain categories of deportees are counted in each wave.</p>",
"31": "<p><strong>wayhî bišlōšîm wĕšebaʿ šānâ lĕgālût Yĕhôyākîn melek-Yĕhûdâ</strong> — &quot;In the thirty-seventh year of Jehoiachin king of Judah&apos;s exile, on the twenty-fifth day of the twelfth month, Evil-merodach king of Babylon in the year he became king... lifted up the head of Jehoiachin.&quot; The book&apos;s final episode: Jehoiachin released and honored under Evil-merodach (Amel-Marduk, 562-560 BC). The phrase <em>nāśāʾ ʾet-rōʾš Yĕhôyākîn</em> (lifted up his head) — <em>nāśāʾ rōʾš</em> means both to lift the head (honor) and appears in Gen 40:13 for Pharaoh&apos;s release of the cupbearer. The MKT renders &quot;lifted up the head of Jehoiachin&quot; preserving the idiom.</p>",
"32": "<p><strong>waydabbēr ʾittô ṭōbôt</strong> — &quot;He treated him with respect (<em>ṭōbôt</em>, good things) and gave him a seat of honor above the other captive kings in Babylon.&quot; The elevation above other captive kings shows political rehabilitation — Jehoiachin is treated as a legitimate king in the Babylonian court, not merely a prisoner. This detail was confirmed by the Weidner Tablets (Babylonian ration tablets) discovered in Berlin which list oil rations for &quot;Yaukin king of Judah&quot; and his sons.</p>",
"33": "<p><strong>wĕhēlîp ʾēt bigdê kilʾô ûʾākal leḥem lĕpānāyw tāmîd</strong> — &quot;So Jehoiachin changed out of his prison clothes and ate regularly at the king&apos;s table for the rest of his life.&quot; Prison clothes exchanged for palace clothes — the restoration of dignity through clothing. <em>Leḥem... tāmîd</em> (bread/food... regularly) — the covenant-provision formula: sustained at the king&apos;s table. The MKT renders &quot;for the rest of his life&quot; (<em>kol-yĕmê ḥayyāyw</em>) to mark the permanence of the rehabilitation.</p>",
"34": "<p><strong>wĕʾarḥātô ʾarḥat tāmîd nittĕnâ-lô mēʾēt melek-Bābel dĕbar-yôm bĕyômô ʿad-yôm mōtô</strong> — &quot;As for his food allowance, a regular daily portion was granted him by the king of Babylon, every day until his death.&quot; The book ends with a daily food allowance for the Davidic heir — a small mercy extended by a pagan king. The ending is deliberately quiet: no restoration of the kingdom, no return to Jerusalem, just daily bread from a foreign king. Yet the Davidic line survives; the covenant is not extinguished. The MKT renders <em>dĕbar-yôm bĕyômô</em> (the matter of a day in its day) as &quot;every day&quot; — the idiom for daily provision. Jeremiah ends where it began: in the shadow of Babylon, with a remnant alive, and the covenant word still in force.</p>"
}
}

def main():
    existing = load_comm('mkt-original', 'jeremiah')
    merge_comm(existing, JEREMIAH)
    save_comm('mkt-original', 'jeremiah', existing)
    print('Jeremiah 51-52 mkt-original written.')

if __name__ == '__main__':
    main()
